if [[ "$*" == *fullSweep* || "$*" == *all* ]]
then
    # Edit this to sweep over a smaller range
    # typeA bytesA typeB bytesB

    typesAndBytes=(
        int16 2 int16 2
        int16 2 cint16 4
        int16 2 int32 4
        int16 2 cint32 8
        cint16 4 int16 2
        cint16 4 cint16 4
        cint16 4 int32 4
        cint16 4 cint32 8
        int32 4 int16 2
        int32 4 int32 4
        int32 4 cint16 4
        int32 4 cint32 8
        cint32 8 int16 2
        cint32 8 cint16 4
        cint32 8 int32 4
        cint32 8 cint32 8
        float 4 float 4
        float 4 cfloat 8
        cfloat 8 float 4
        cfloat 8 cfloat 8
    )

    dims=(
        16 16 16
        64 64 32
    )

    for (( typeI=0; typeI<${#typesAndBytes[@]}; typeI+=4 )); do
        echo "${typesAndBytes[$typeI]},${typesAndBytes[`expr $typeI + 2 `]}"
        dTypeA=${typesAndBytes[$typeI]}
        dBytesA=${typesAndBytes[`expr $typeI + 1`]}
        dTypeB=${typesAndBytes[`expr $typeI + 2 `]}
        dBytesB=${typesAndBytes[`expr $typeI + 3 `]}
        # Scrape int number from inB type (arbtrirary)
        shift=${dTypeB#*int}
        if [[ $dTypeB == *float ]]; then
            shift=0
        fi
        maxBytes=16384
        maxSizeA=$(( $maxBytes / $dBytesA ))
        maxSizeB=$(( $maxBytes / $dBytesB ))
        minElems=4 # should be true for all types
        if [ "$maxSizeA" -lt "$maxSizeB" ]; then
            maxSizeBoth=$maxSizeA
        else
            maxSizeBoth=$maxSizeB
        fi



        dims=(
            $minElems $minElems $minElems
            16 16 16
            $(( $minElems * 3 )) $(( $minElems * 7 )) $(( $minElems * 5 ))
            $(($maxSizeA / $minElems)) $minElems $minElems                          # Max on A ; min on AB and B.
            $minElems $minElems $(( $maxSizeB / $minElems ))                        # Max on B ; min on AB and A.
            $minElems $(( $maxSizeBoth / $minElems )) $minElems                     # Max on AB; min others.
            $minElems $(( $minElems * 8 )) $(( $maxSizeB / ( $minElems * 8 ) ))                        #  BMax/8 ; min on A.
            $(( $maxSizeA / ( $minElems * 8 ) )) $(( $minElems * 8 )) $minElems                        #  AMax/8 ; min on A.
        )

        #$maxSize / $dBytesA \* $minElems `; maxElemsB=`expr $maxSize / $dBytesB `"
        #echo "${dims[@]}"


        if [[ $dTypeA == int16 && $dTypeB == int16 ]]; then
            tiles=(
                4 4 4 #best
                #2 4 8
                #4 2 8
            )
        fi
        # 32 bit x 16 bit
        if [[ ( $dTypeA == cint16 || $dTypeA == int32 ) && ( $dTypeB == int16 ) ]]; then
            tiles=(
                #2 4 8
                #4 4 4
                #4 2 4
                #2 2 4 #good
                #2 4 4 #good
                4 4 2 #good (marginal best)
                #2 2 8
            )
        fi
        # 16 bit x 32 bit
        if [[ ( $dTypeA == int16 ) && ( $dTypeB == cint16 || $dTypeB == int32 ) ]]; then
            tiles=(
                4 2 2 #best
                #4 4 4
            )
            #if [[ $dTypeB == int32 ]]; then
            #    tiles+=( 2 4 8 )
            #fi
        fi
        # 32 bit x 32 bit
        if [[ ( ( $dTypeA == cint16 || $dTypeA == int32 ) && ( $dTypeB == cint16 || $dTypeB == int32) ) || ( $dTypeA == float && $dTypeB == float )  ]]; then
            tiles=(
                #4 2 4
                #2 2 2
                #2 4 2
                #2 8 2
                #4 2 2 #good
                4 4 2 #good - marginally better
                #2 4 4 #good
            )
        fi

        # 64 bit x 16 bit
        if [[ $dTypeA == cint32 && $dTypeB == int16 ]]; then
            tiles=(
                2 4 2 # good (best)
                #2 8 2
                #2 4 4 # good
                #4 4 2
            )
        fi
        # 16 bit x 64 bit
        if [[ $dTypeA == int16 && $dTypeB == cint32 ]]; then
            tiles=(
                2 4 2 #best
                #2 4 4
                #2 8 2
                #4 4 2
            )
        fi
        # 64 bit x 32 bit
        if [[ ( $dTypeA == cint32 ) && ( $dTypeB == cint16 || $dTypeB == int32 ) ]]; then
            tiles=(
                2 2 2 #best (marginal)
                #2 4 2 #good
            )
            #if [[ $dTypeB == int32 ]]; then
            #    tiles+=( 1 2 2 )
            #fi
        fi
        # 32 bit x 64 bit
        if [[ ( $dTypeA == cint16 || $dTypeA == int32 ) && ( $dTypeB == cint32 )  ]]; then
            tiles=(
                2 2 2 #best
                #2 4 2
            )
        fi
        # 64 bit x 64 bit
        if [[ $dTypeA == cint32 && $dTypeB == cint32 ]]; then
            tiles=(
                #1 2 2
                #2 2 1
                2 2 2 #best
            )
        fi
        if [[ ( $dTypeA == cfloat && $dTypeB == float ) || ( $dTypeA == float && $dTypeB == cfloat ) ]]; then
            tiles=(
                #2 2 2
                2 4 2 #best (marginally)
            )
        fi
        if [[ $dTypeA == cfloat && $dTypeB == cfloat ]]; then
            tiles=(
                #2 2 2
                #2 2 4
                #2 4 2
                4 2 2 #best
            )
        fi


        for (( dimI=0; dimI<${#dims[@]}; dimI+=3 )); do
            dimA=${dims[$dimI]}
            dimAB=${dims[`expr $dimI + 1 `]}
            dimB=${dims[`expr $dimI + 2 `]}

            echo "$dimA x $dimAB x $dimB"

            addTilingA=$(($RANDOM % 2))
            addTilingB=$(($RANDOM % 2))
            addDetilingOut=$(($RANDOM % 2))
            if [[ ( $dimAB == $minElems ) ]]; then
                addTilingA=0
                addTilingB=0
                addDetilingOut=0
            fi
            if [[ $dTypeB == int16 ]]; then
                addTilingB=0
            fi

            ## increase the size if it's too small to fit in a 512b buffer that's used in the tiler.
            if [[ ( $(( $dBytesA * $dimA * $dimAB )) -lt $(( 512 / 8 )) ) && $addTilingA == 1 ]]; then
                dimA=$(( $dimA * 2 ))
            fi
            if [[ ( $(( $dBytesB * $dimB * $dimAB )) -lt $(( 512 / 8 )) ) && $addTilingB == 1 ]]; then
                dimB=$(( $dimB * 2 ))
            fi
            if [[ ( $(( ( $maxBytes / $maxSizeBoth ) * $dimA * $dimB )) -lt $(( 512 / 8 )) ) && $addDetilingOut == 1 ]]; then
                dimB=$(( $dimB * 2 ))
            fi

            # decrease the size if its at the max size and we're using the tiler.
            if [[ ( $(( $dimA * $dimAB )) == $maxSizeA ) && $addTilingA == 1  ]]; then
                if [ "$dimA" -gt "$minElems" ]; then
                    dimA=$(( $dimA / 2 ))
                else
                    dimAB=$(( $dimAB / 2 ))
                fi
            fi

            if [[ ( $(( $dimB * $dimAB )) == $maxSizeB ) && $addTilingB == 1  ]]; then
                if [ "$dimB" -gt "$minElems" ]; then
                    dimB=$(( $dimB / 2 ))
                else
                    dimAB=$(( $dimAB / 2 ))
                fi
            fi

            if [[ ( ( $(( $dimA * $dimB )) == $maxSizeBoth ) && $addDetilingOut == 1 ) ]]; then
                if [ "$dimB" -gt "$minElems" ]; then
                    dimB=$(( $dimB / 2 ))
                else
                    dimA=$(( $dimA / 2 ))
                fi
            fi
            # if resultant output dimensions are still too large; reduce size to fit.
            if [[ $(( $dimA * $dimB )) -gt $maxSizeBoth ]]; then
                scaling=$(( $maxSizeBoth / ( $dimA * $dimB ) ))
                if [ $(( $dimB / $scaling )) -ge "$minElems" ]; then
                    dimB=$(( $dimB / $scaling ))
                else
                    dimA=$(( $dimA / $scaling ))
                fi
            fi

            echo "$dimA x $dimAB x $dimB"


            for (( tileI=0; tileI<${#tiles[@]}; tileI+=3 )); do
                tileA=${tiles[$tileI]}
                tileAB=${tiles[`expr $tileI + 1 `]}
                tileB=${tiles[`expr $tileI + 2 `]}
                #echo "$dimA x $dimAB x $dimB"
                test_arr[$LINENO]="make all T_DATA_A=$dTypeA T_DATA_B=$dTypeB P_DIM_A=$dimA P_DIM_AB=$dimAB P_DIM_B=$dimB P_ADD_TILING_A=$addTilingA P_ADD_TILING_B=$addTilingB P_ADD_DETILING_OUT=$addDetilingOut P_ADD_TILING_A=$addTilingA  DIM_A_TILE=$tileA DIM_AB_TILE=$tileAB DIM_B_TILE=$tileB P_SHIFT=$shift RESULTS_DIR=./results_sweep/${dTypeA}_${dTypeB}_${dimA}_${dimAB}_${dimB}_${tileA}_${tileAB}_${tileB}_${shift} "

            done
        done
    done

fi

# Randomized testing
if [[ "$*" == *randomized* ]]
then
    # read from randomized test file
    while IFS= read -r line; do
        test_arr[${#test_arr[*]}]="$line"
    done < randomized_tests.txt
fi

# echo "Adding the following args to make commands: ${make_args[@]}"
# Ensure each test goes into a seperate runmake
for i in "${!test_arr[@]}"; do
    # append make args to each make command
    if [[ ${test_arr[$i]} == make* ]]
    then
        test_arr[$i]="${test_arr[$i]} ${make_args[@]}"
    fi
    test_arr[$i]="${test_arr[$i]} |& tee runmake_logs/runmake_${i}.log "
done

makeCmd_raw=()
otherCmd_raw=()

for i in "${!test_arr[@]}"; do
    # append make args to each make command
    if [[ ${test_arr[$i]} == make* ]]; then
        makeCmd_raw[${#makeCmd_raw[*]}]=${test_arr[$i]}
    else
        otherCmd_raw[${#otherCmd_raw[*]}]=${test_arr[$i]}
    fi
done
# for i in "${!makeCmd_raw[@]}"; do
#     echo ${makeCmd_raw[$i]}
# done

if [[ "$*" == *-append* ]]
then
    verify_tests=0
    new_test_names=$(python3 $runmakeDir/../common/scripts/populate_params.py $run_type $runmakeDir "${makeCmd_raw[@]}" -append)
else
    new_test_names=$(python3 $runmakeDir/../common/scripts/populate_params.py $run_type $runmakeDir "${makeCmd_raw[@]}")
fi
multi_params_file=multi_params_$run_type

if [[ $run_type == "jenkins" ]]
then
    python3 $runmakeDir/../common/scripts/populate_params.py clear_params $runmakeDir
    $runmakeDir/runmake.sh -run_type checkin -no_test_run
    exit_code1=$?
    $runmakeDir/runmake.sh -run_type qor -no_test_run
    exit_code2=$?
    if [[ $exit_code1 -eq 1 || $exit_code2 -eq 1 ]]; then
        exit 1
    fi
    $runmakeDir/runmake.sh -run_type checkin -append -no_test_run -no_test_verify
    $runmakeDir/runmake.sh -run_type qor -append -no_test_run -no_test_verify
    multi_params_file=multi_params
    run_tests=0
    verify_tests=0
fi

if [[ $verify_tests == 1 ]]
then
    test_lines_string=${!test_arr[@]}
    echo Verifying $run_type test suite...
    python3 $runmakeDir/../common/scripts/verify_multi_params.py --ip $(basename $runmakeDir) --multi_params $runmakeDir/$multi_params_file.json --test_lines "$test_lines_string" --gen_test_file --test_suite $run_type
    exit_code=$?
    if [[ $exit_code -eq 1 ]]; then
        exit 1
    fi
fi

if [[ $run_tests == 1 ]]
then
    timestamp=$(date +"%y%m%d_%H%M")
    echo "Start of Batch Run ($timestamp)" | tee ./runmake_logs/runmake.log
    $runmakeDir/../common/scripts/run_batch.sh -func $runmakeDir -params $multi_params_file -batch_suffix $timestamp
fi
